<section class="panel form-panel wide-form"><div class="panel-header"><div><span class="section-kicker">Commercial & Ventes</span><h2>Créer un devis client</h2><p class="ui-page-intro">Sélectionnez le client, définissez la validité de l’offre et renseignez les produits ou prestations proposés.</p></div><a class="btn btn-secondary" href="<?= url('quotations/index'); ?>"><i class="bi bi-arrow-left"></i> Retour aux devis</a></div><form method="post" action="<?= url('quotations/store'); ?>" data-validate><?= Csrf::field(); ?><div class="form-grid"><label>Client <select name="client_id" required><option value="">Sélectionner un client</option><?php foreach($clients as $c): ?><option value="<?= (int)$c['id']; ?>"><?= e($c['name']); ?></option><?php endforeach; ?></select></label><label>Date du devis <input type="date" name="quote_date" required value="<?= date('Y-m-d'); ?>"></label><label>Date de validité <input type="date" name="valid_until"></label><label class="span-2">Notes commerciales <textarea name="notes" rows="3" placeholder="Conditions, délai ou informations destinées au client…"></textarea></label></div><div class="line-items"><div class="line-items-header"><h3>Produits et prestations proposés</h3></div><div class="fund-item-row construction-row"><label>Produit <select name="items[product_id][]"><option value="">Prestation libre</option><?php foreach($products as $p): ?><option value="<?= (int)$p['id']; ?>"><?= e($p['name']); ?> · Stock <?= e($p['stock_quantity']); ?></option><?php endforeach; ?></select></label><label>Description <input name="items[description][]" required placeholder="Désignation de la ligne"></label><label>Quantité <input type="number" step="0.01" min="0.01" name="items[quantity][]" required value="1"></label><label>Prix unitaire <input type="number" step="0.01" name="items[unit_price][]" required></label><label>Coût estimé <input type="number" step="0.01" name="items[unit_cost][]" required></label><label>Taxe % <input type="number" step="0.01" name="items[tax_rate][]" value="0"></label></div></div><div class="form-actions"><a class="btn btn-secondary" href="<?= url('quotations/index'); ?>">Annuler</a><button class="btn btn-primary" type="submit"><i class="bi bi-file-earmark-check"></i> Créer le devis</button></div></form></section>
